diff --git a/client/src/types/ktp.types.ts b/client/src/types/ktp.types.ts
index 51b4de5..1b85ffa 100644
--- a/client/src/types/ktp.types.ts
+++ b/client/src/types/ktp.types.ts
@@ -25,3 +25,61 @@ export interface KtpTopicInput {
   order?: number;
   code?: string;
 }
+
+// ==================== Knowledge Components (подтемы) + банк вопросов ====================
+
+export type KnowledgeComponentStatus = 'proposed' | 'confirmed';
+
+export interface KnowledgeComponent {
+  _id: string;
+  title: string;
+  description?: string;
+  order: number;
+  status: KnowledgeComponentStatus;
+}
+
+export interface KnowledgeComponentInput {
+  id?: string;
+  title?: string;
+  description?: string;
+  order?: number;
+  status?: KnowledgeComponentStatus;
+}
+
+export interface BankCoverageKc {
+  kcId: string;
+  title: string;
+  active: number;
+}
+
+export interface BankCoverage {
+  totalActive: number;
+  perKc: BankCoverageKc[];
+  unassigned: number;
+}
+
+export interface BankGenerateResult {
+  created: number;
+  rejected: number;
+  coverage: BankCoverage;
+}
+
+export type QuestionItemStatus = 'draft' | 'active' | 'retired';
+
+/** Item банка для admin-просмотра (с правильным ответом). */
+export interface BankItem {
+  _id: string;
+  knowledgeNodeId: string;
+  knowledgeComponentIds: string[];
+  difficulty: number;
+  status: QuestionItemStatus;
+  question: {
+    questionType: string;
+    questionText: string;
+    options?: string[];
+    correctOption?: string;
+    aiExplanation?: string;
+  };
+  qualityStats?: { timesUsed: number; timesCorrect: number };
+  createdAt?: string;
+}

diff --git a/server/src/controllers/ktp.controller.ts b/server/src/controllers/ktp.controller.ts
index d854d1b..71e5c2b 100644
--- a/server/src/controllers/ktp.controller.ts
+++ b/server/src/controllers/ktp.controller.ts
@@ -132,6 +132,19 @@ class KtpController {
     const data = await questionBankService.generateForCoverage(subjectId, topicId, { minPerKc, difficulty });
     success(res, data, 'Question bank topped up', 201);
   }
+
+  /** Admin: просмотр сгенерированных вопросов банка узла (с правильными ответами). */
+  async listBankItems(req: Request, res: Response): Promise<void> {
+    const { subjectId, topicId } = req.params;
